class Solution:
    def getWinner(self, arr, k):
        """
        :type arr: List[int]
        :type k: int
        :rtype: int
        """
        current = arr[0]
        wins = 0

        for i in range(1, len(arr)):
            if current > arr[i]:
                wins += 1
            else:
                current = arr[i]
                wins = 1

            # If someone wins k consecutive games, they're done
            if wins == k:
                return current

            # If reaches maximum element, they win rest
            if current == max(arr):
                return current

        return current
